import React from 'react';
import './FeaturedServices.css';

const FeaturedServices = () => {
  const services = [
    {
      id: 1,
      icon: (
        <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
          <path d="M16 3H5C3.9 3 3 3.9 3 5V16C3 17.1 3.9 18 5 18H16C17.1 18 18 17.1 18 16V5C18 3.9 17.1 3 16 3ZM7 7L10.5 9L14 7V5H7V7Z" fill="currentColor"/>
          <path d="M20 6V17H22V6C22 4.9 21.1 4 20 4H7V6H20Z" fill="currentColor"/>
        </svg>
      ),
      title: "Free Shipping",
      description: "Free Shipping On All Us Order or Order Above $200"
    },
    {
      id: 2,
      icon: (
        <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
          <path d="M12 1C8.1 1 5 4.1 5 8C5 11.9 8.1 15 12 15C15.9 15 19 11.9 19 8C19 4.1 15.9 1 12 1ZM12 13C9.2 13 7 10.8 7 8C7 5.2 9.2 3 12 3C14.8 3 17 5.2 17 8C17 10.8 14.8 13 12 13Z" fill="currentColor"/>
          <path d="M21 16H3C2.4 16 2 16.4 2 17V19C2 20.1 2.9 21 4 21H20C21.1 21 22 20.1 22 19V17C22 16.4 21.6 16 21 16ZM20 19H4V18H20V19Z" fill="currentColor"/>
        </svg>
      ),
      title: "Support 24/7",
      description: "Contact Us 24 Hours A Day, 7 Days A Week"
    },
    {
      id: 3,
      icon: (
        <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
          <path d="M9 11H7L9 13L11 11H9ZM13 5V7H9.5L13 3.5V5H13ZM19 3H5C3.9 3 3 3.9 3 5V19C3 20.1 3.9 21 5 21H19C20.1 21 21 20.1 21 19V5C21 3.9 20.1 3 19 3ZM19 19H5V5H19V19Z" fill="currentColor"/>
        </svg>
      ),
      title: "07 Days Return",
      description: "Simply Return It Within 30 Days For An Exchange"
    },
    {
      id: 4,
      icon: (
        <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
          <path d="M18 8H17V6C17 3.24 14.76 1 12 1C9.24 1 7 3.24 7 6V8H6C4.9 8 4 8.9 4 10V20C4 21.1 4.9 22 6 22H18C19.1 22 20 21.1 20 20V10C20 8.9 19.1 8 18 8ZM12 17C10.9 17 10 16.1 10 15C10 13.9 10.9 13 12 13C13.1 13 14 13.9 14 15C14 16.1 13.1 17 12 17ZM15.1 8H8.9V6C8.9 4.29 10.29 2.9 12 2.9C13.71 2.9 15.1 4.29 15.1 6V8Z" fill="currentColor"/>
        </svg>
      ),
      title: "100% Payment Secure",  
      description: "We Ensure Secure Payment with PayPal And Card"
    }
  ];

  return (
    <section className="featured-services">
      <div className="services-container">
        {services.map(service => (
          <div key={service.id} className="service-card">
            <div className="service-icon">{service.icon}</div>
            <div className="service-content">
              <h3 className="service-title">{service.title}</h3>
              <p className="service-description">{service.description}</p>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
};

export default FeaturedServices;
